async (params, browser) => {
  // Search Medium
  await browser.open(`https://medium.com/search?q=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('article, [data-testid=\'postPreview\'], div[class*=\'postArticle\'], div[role=\'link\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract article results
  const search_results = await browser.evaluate(`const results = []; const articles = document.querySelectorAll('article, [data-testid="postPreview"], div[class*="postArticle"]'); for (let i = 0; i < Math.min(articles.length, 15); i++) { const el = articles[i]; const titleEl = el.querySelector('h2, h3, [class*="title"]'); const authorEl = el.querySelector('a[data-testid="authorName"], a[rel="author"], [class*="author"] a, p[class*="author"]'); const pubEl = el.querySelector('[class*="publication"] a, a[data-testid="publicationName"]'); const clapsEl = el.querySelector('[class*="clap"] span, button[data-testid="clap"] span, [class*="clapCount"]'); const readTimeEl = el.querySelector('[class*="readingTime"], span[class*="read-time"], [class*="readTime"]'); const dateEl = el.querySelector('time, span[class*="date"], [datetime]'); const linkEl = el.querySelector('a[href*="/p/"], a[data-testid="postPreview-title"], h2 a, h3 a'); const imgEl = el.querySelector('img[src*="miro.medium"], img[loading]'); const subtitleEl = el.querySelector('h3, [class*="subtitle"], [class*="preview"] p'); results.push({ title: titleEl ? titleEl.textContent.trim() : '', subtitle: subtitleEl ? subtitleEl.textContent.trim().substring(0, 200) : '', author: authorEl ? authorEl.textContent.trim() : '', publication: pubEl ? pubEl.textContent.trim() : '', claps: clapsEl ? clapsEl.textContent.trim() : '', read_time: readTimeEl ? readTimeEl.textContent.trim() : '', date: dateEl ? (dateEl.getAttribute('datetime') || dateEl.textContent.trim()) : '', url: linkEl ? linkEl.href : '', image: imgEl ? imgEl.getAttribute('src') : '' }); } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
